  <script>
    const rawValues = {};
    const computedValues = {};
    const dependents = {};

    function evaluateCell(cellId, visited = new Set()) {
      if (visited.has(cellId)) {
        return '#CYCLE';
      }
      visited.add(cellId);

      const raw = rawValues[cellId];
      if (!raw) {
        return '0';
      }

      if (!raw.startsWith('=')) {
        return raw;
      }

      const formula = raw.slice(1);
      const cellRefs = formula.match(/[A-J][1-9][0-9]?/g);
      if (!cellRefs) {
        try {
          return String(eval(formula));
        } catch (e) {
          return '#ERR';
        }
      }

      for (const ref of cellRefs) {
        if (!/^[A-J][1-9][0-9]?$/.test(ref)) {
          return '#ERR';
        }
      }

      let expression = formula;
      for (const ref of cellRefs) {
        const value = evaluateCell(ref, new Set(visited));
        if (value === '#ERR' || value === '#CYCLE') {
          return value;
        }
        expression = expression.replace(ref, parseFloat(value) || 0);
      }

      try {
        const result = eval(expression);
        return String(result);
      } catch (e) {
        return '#ERR';
      }
    }

    function updateDependencies(cellId, newFormula) {
      const oldFormula = rawValues[cellId];
      if (oldFormula && oldFormula.startsWith('=')) {
        const oldRefs = oldFormula.slice(1).match(/[A-J][1-9][0-9]?/g) || [];
        for (const ref of oldRefs) {
          const index = dependents[ref]?.indexOf(cellId);
          if (index !== -1) {
            dependents[ref].splice(index, 1);
          }
        }
      }

      if (newFormula.startsWith('=')) {
        const newRefs = newFormula.slice(1).match(/[A-J][1-9][0-9]?/g) || [];
        for (const ref of newRefs) {
          if (!dependents[ref]) {
            dependents[ref] = [];
          }
          dependents[ref].push(cellId);
        }
      }
    }

    function getAllDependents(cellId) {
      const visited = new Set();
      const queue = [];
      const initialDeps = dependents[cellId] || [];
      for (const dep of initialDeps) {
        queue.push(dep);
      }
      while (queue.length > 0) {
        const current = queue.shift();
        if (visited.has(current)) continue;
        visited.add(current);
        const deps = dependents[current] || [];
        for (const dep of deps) {
          if (!visited.has(dep)) {
            queue.push(dep);
          }
        }
      }
      return Array.from(visited);
    }

    function recalculateCell(cellId) {
      const newValue = evaluateCell(cellId);
      computedValues[cellId] = newValue;
      const input = document.getElementById('cell-' + cellId);
      if (input) {
        input.value = newValue;
      }
      const dependentsList = getAllDependents(cellId);
      for (const dep of dependentsList) {
        recalculateCell(dep);
      }
    }

    window.sheet = {
      set: function(cellId, value) {
        rawValues[cellId] = value;
        updateDependencies(cellId, value);
        recalculateCell(cellId);
      },
      get: function(cellId) {
        return computedValues[cellId];
      },
      raw: function(cellId) {
        return rawValues[cellId];
      }
    };

    document.querySelectorAll('input').forEach(input => {
      input.addEventListener('focus', function() {
        const cellId = this.id.replace('cell-', '');
        this.value = rawValues[cellId] || '';
      });

      input.addEventListener('blur', function() {
        const cellId = this.id.replace('cell-', '');
        const newValue = this.value;
        sheet.set(cellId, newValue);
      });

      input.addEventListener('keydown', function(e) {
        if (e.key === 'Enter') {
          const cellId = this.id.replace('cell-', '');
          const newValue = this.value;
          sheet.set(cellId, newValue);
          this.blur();
        }
      });
    });

    document.getElementById('export').addEventListener('click', function() {
      let csv = '';
      for (let row = 1; row <= 10; row++) {
        const rowValues = [];
        for (let col = 0; col < 10; col++) {
          const cellId = String.fromCharCode(65 + col) + row;
          rowValues.push(computedValues[cellId] || '');
        }
        csv += rowValues.join(',') + '\n';
      }
      document.getElementById('csv').value = csv;
    });
  </script>
